const msg = $input.first().json.message;
const testo = (msg.text || '').trim();
const chatId = msg.chat.id;
const nome = msg.from.first_name || 'utente';

// Parsing comandi
// Formato atteso:
// /avviso Domani siamo chiusi
// /promo Menù pranzo 12€ - Primo+secondo+acqua
// /orari Lun-Ven 08:00-20:00 | Sab 09:00-14:00
// /telefono 02 1234567
// /info parcheggio Disponibile in via Roma
// /menu aggiungi Primi | Spaghetti al pomodoro | | 10
// /menu rimuovi Primi | Spaghetti al pomodoro
// /stato  (mostra riepilogo dati)

const righe = testo.split('\n');
const prima = righe[0];
const parti = prima.split(' ');
const comando = parti[0].toLowerCase();
const resto = parti.slice(1).join(' ');

return [{
  json: {
    chatId,
    nome,
    comando,
    resto,
    testoCompleto: testo
  }
}];

// Legge il JSON del cliente, aggiorna il campo avviso
const fs = require('fs');
const path = '/weblocal/clienti/{{ $json.chatId }}/dati-cliente.json';

let dati = JSON.parse(fs.readFileSync(path, 'utf8'));
dati.avviso = $json.resto;
fs.writeFileSync(path, JSON.stringify(dati, null, 2));

return [{ json: { ok: true, campo: 'avviso', valore: $json.resto, chatId: $json.chatId } }];

const fs = require('fs');
const path = '/weblocal/clienti/{{ $json.chatId }}/dati-cliente.json';
const parti = $json.resto.split('-');

let dati = JSON.parse(fs.readFileSync(path, 'utf8'));
dati.promozione = {
  attiva: true,
  testo: parti[0]?.trim() || $json.resto,
  dettaglio: parti[1]?.trim() || ''
};
fs.writeFileSync(path, JSON.stringify(dati, null, 2));

return [{ json: { ok: true, campo: 'promozione', valore: $json.resto, chatId: $json.chatId } }];

// Formato: Lun-Ven 08:00-20:00 | Sab 09:00-14:00 | Dom chiuso
const fs = require('fs');
const path = '/weblocal/clienti/{{ $json.chatId }}/dati-cliente.json';

const orari = $json.resto.split('|').map(o => {
  const p = o.trim().split(' ');
  return { giorno: p[0], ore: p.slice(1).join(' ') };
});

let dati = JSON.parse(fs.readFileSync(path, 'utf8'));
dati.orari = orari;
fs.writeFileSync(path, JSON.stringify(dati, null, 2));

return [{ json: { ok: true, campo: 'orari', chatId: $json.chatId } }];

const fs = require('fs');
const path = '/weblocal/clienti/{{ $json.chatId }}/dati-cliente.json';

let dati = JSON.parse(fs.readFileSync(path, 'utf8'));
dati.telefono = $json.resto.trim();
fs.writeFileSync(path, JSON.stringify(dati, null, 2));

return [{ json: { ok: true, campo: 'telefono', valore: $json.resto, chatId: $json.chatId } }];

const fs = require('fs');
const path = '/weblocal/clienti/{{ $json.chatId }}/dati-cliente.json';
const dati = JSON.parse(fs.readFileSync(path, 'utf8'));

const orariStr = dati.orari.map(o => `${o.giorno}: ${o.ore}`).join('\n');

const testo = `📊 *Stato sito: ${dati.nome}*\n\n` +
  `📍 ${dati.indirizzo}\n` +
  `📞 ${dati.telefono}\n\n` +
  `🕐 *Orari:*\n${orariStr}\n\n` +
  `📢 *Avviso:* ${dati.avviso || '(nessuno)'}\n` +
  `🎉 *Promo:* ${dati.promozione?.attiva ? dati.promozione.testo : '(nessuna)'}\n\n` +
  `🌐 Vedi sito: https://weblocal.it/${$json.chatId}`;

return [{ json: { chatId: $json.chatId, testo } }];

// Unifica la risposta da tutti i rami
const input = $input.first().json;
let testo;

if (input.testo) {
  testo = input.testo; // già formattato (stato/aiuto)
} else if (input.ok) {
  const etichette = {
    avviso: '📢 Avviso',
    promozione: '🎉 Promozione',
    orari: '🕐 Orari',
    telefono: '📞 Telefono'
  };
  testo = `✅ *${etichette[input.campo] || input.campo} aggiornato!*\n\nIl sito è già live con le modifiche.`;
} else {
  testo = '❌ Comando non riconosciuto. Scrivi /aiuto per vedere i comandi disponibili.';
}

return [{ json: { chatId: input.chatId, testo } }];
